import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

describe("mergeIntervals", () => {
  // Bug caught: returning something other than [] for empty input, or crashing.
  it("returns [] for empty input", () => {
    expect(mergeIntervals([])).toEqual([]);
  });

  // Bug caught: a lone interval being dropped or altered.
  it("passes a single interval through unchanged", () => {
    expect(mergeIntervals([[2, 5]])).toEqual([[2, 5]]);
  });

  // Bug caught: merging intervals that share no points (over-eager merge).
  it("keeps disjoint intervals separate", () => {
    expect(mergeIntervals([[1, 2], [5, 8]])).toEqual([[1, 2], [5, 8]]);
  });

  // Bug caught: failing to merge genuinely overlapping intervals.
  it("merges overlapping intervals", () => {
    expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
  });

  // --- Boundary attack around "touching" (start == previous end) ---

  // Bug caught: treating touching intervals as disjoint (using < instead of <=).
  it("merges intervals that touch exactly at the boundary", () => {
    expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
  });

  // Bug caught: an off-by-one that merges intervals separated by a gap of 1
  // (using start <= last[1] + 1 instead of start <= last[1]).
  it("keeps intervals separated by a gap of one apart", () => {
    expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
  });

  // --- Boundary attack around end extension ---

  // Bug caught: setting last end to the incoming end instead of the max, which
  // would wrongly shrink a merged interval that fully contains the next one.
  it("keeps the larger end when the next interval is nested inside", () => {
    expect(mergeIntervals([[1, 10], [3, 5]])).toEqual([[1, 10]]);
  });

  // Bug caught: extending only by one step and not folding a whole chain.
  it("folds a chain where each interval overlaps the running merge", () => {
    expect(mergeIntervals([[1, 3], [2, 5], [4, 8]])).toEqual([[1, 8]]);
  });

  // Bug caught: a later interval fully swallowed by an earlier wide one still
  // contributing its (smaller) end.
  it("absorbs intervals fully contained in an earlier one", () => {
    expect(mergeIntervals([[1, 20], [3, 5], [6, 9]])).toEqual([[1, 20]]);
  });

  // --- Sorting ---

  // Bug caught: assuming input is pre-sorted and emitting out-of-order output.
  it("sorts the output by start ascending regardless of input order", () => {
    expect(mergeIntervals([[8, 10], [1, 3], [4, 6]])).toEqual([
      [1, 3],
      [4, 6],
      [8, 10],
    ]);
  });

  // Bug caught: relying on input order so that an overlap only merges when the
  // wider interval happens to come first.
  it("merges overlapping intervals given in reverse order", () => {
    expect(mergeIntervals([[3, 6], [1, 4]])).toEqual([[1, 6]]);
  });

  // Bug caught: mishandling ties on start (equal starts should still collapse).
  it("collapses intervals that share the same start", () => {
    expect(mergeIntervals([[1, 2], [1, 5]])).toEqual([[1, 5]]);
  });

  // Bug caught: dropping exact duplicates or emitting them twice.
  it("collapses exact duplicate intervals into one", () => {
    expect(mergeIntervals([[2, 4], [2, 4]])).toEqual([[2, 4]]);
  });

  // --- Point intervals (start == end) ---

  // Bug caught: rejecting a valid zero-length interval as start > end.
  it("accepts a point interval where start equals end", () => {
    expect(mergeIntervals([[5, 5]])).toEqual([[5, 5]]);
  });

  // Bug caught: not merging a point interval that touches the end of another.
  it("merges a point interval touching the end of an interval", () => {
    expect(mergeIntervals([[1, 5], [5, 5]])).toEqual([[1, 5]]);
  });

  // --- Negative and mixed values ---

  // Bug caught: sorting numerically wrong (e.g. lexicographic) with negatives.
  it("orders and merges intervals spanning negative values", () => {
    expect(mergeIntervals([[-1, 2], [-10, -5], [1, 4]])).toEqual([
      [-10, -5],
      [-1, 4],
    ]);
  });

  // --- Error behavior (start > end) ---

  // Bug caught: silently accepting an inverted interval.
  it("throws RangeError when a pair has start greater than end", () => {
    expect(() => mergeIntervals([[5, 4]])).toThrow(RangeError);
  });

  // Bug caught: an off-by-one where start == end + 1 slips past the check but a
  // clearly inverted pair should be rejected even when it is not the first one.
  it("throws RangeError for an inverted pair anywhere in the list", () => {
    expect(() => mergeIntervals([[1, 3], [8, 2]])).toThrow(RangeError);
  });

  // Bug caught: using >= (rejecting valid point intervals) instead of >.
  it("does not throw for a valid point interval at the check boundary", () => {
    expect(() => mergeIntervals([[7, 7]])).not.toThrow();
  });

  // --- Immutability ---

  // Bug caught: sorting or merging in place, mutating the caller's array/pairs.
  it("does not mutate the input array or its pairs", () => {
    const input = [[3, 6], [1, 4], [10, 12]];
    const snapshot = input.map(([s, e]) => [s, e]);
    mergeIntervals(input);
    expect(input).toEqual(snapshot);
  });

  // Bug caught: returning references into the caller's own pair objects, so that
  // later mutation of the result would corrupt the input.
  it("returns intervals that do not alias the input pairs", () => {
    const pair = [1, 4];
    const input = [pair];
    const result = mergeIntervals(input);
    result[0][1] = 999;
    expect(pair).toEqual([1, 4]);
  });
});

